-- DO NOT EDIT THIS FILE, if you want to configure something, edit the file
-- at this location. ~/.config/hypr/edit_here/source/

-- You can also use the TUI `Hypr Keybind Manager` from the rofi menu to change keybinds. It automatically
-- unbinds keybinds and checks for conflicts. 

-- -------------------------------------------------------------------------------------------------
-- window classes to not have global keybinds applied in
-- -------------------------------------------------------------------------------------------------

local function is_target_app_active()
    local w = hl.get_active_window()
    if not w then return false end
    local class = w.class or ""
    return class == "horizon_tui" or class == "wallpaper_selector.py" or class == "terminal_clipboard.sh"
end

local function cond_bind(key, default_dsp, flags)
    hl.bind(key, function()
        if is_target_app_active() then
            hl.dispatch(hl.dsp.pass({ window = "activewindow" }))
        else
            if default_dsp then
                hl.dispatch(default_dsp)
            else
                hl.dispatch(hl.dsp.pass({ window = "activewindow" }))
            end
        end
    end, flags)
end


