-- Multi MONITOR
-----------------------------------------------------

-- Each monitor gets its own "bank" of 10 workspaces, assigned left-to-right
-- by X position. SUPER+1 always means "workspace 1 on THIS monitor".
--   Monitor 0 (leftmost) → workspaces  1–10
--   Monitor 1            → workspaces 11–20
--   …etc.
--
-- The script handles all the math; these binds just pass the 1-10 slot number.
-- -------------------------------------------------------------------------------------------------

local ws_script = horizon_scripts .. "hypr/multi_monitor_workspace.sh"

-- Helper shorthand so the repeated hl.dsp.exec_cmd calls stay readable
local function ws(action, n)
    return hl.dsp.exec_cmd(ws_script .. " " .. action .. " " .. tostring(n))
end

-- ── Switch to Workspace (Context Relative) ────────────────────────────────────

hl.bind("SUPER + SHIFT + ALT + 1", ws("workspace", 1),  { description = "Switch To Context 1" })
hl.bind("SUPER + SHIFT + ALT + 2", ws("workspace", 2),  { description = "Switch To Context 2" })
hl.bind("SUPER + SHIFT + ALT + 3", ws("workspace", 3),  { description = "Switch To Context 3" })
hl.bind("SUPER + SHIFT + ALT + 4", ws("workspace", 4),  { description = "Switch To Context 4" })
hl.bind("SUPER + SHIFT + ALT + 5", ws("workspace", 5),  { description = "Switch To Context 5" })
hl.bind("SUPER + SHIFT + ALT + 6", ws("workspace", 6),  { description = "Switch To Context 6" })
hl.bind("SUPER + SHIFT + ALT + 7", ws("workspace", 7),  { description = "Switch To Context 7" })
hl.bind("SUPER + SHIFT + ALT + 8", ws("workspace", 8),  { description = "Switch To Context 8" })
hl.bind("SUPER + SHIFT + ALT + 9", ws("workspace", 9),  { description = "Switch To Context 9" })
hl.bind("SUPER + SHIFT + ALT + 0", ws("workspace", 10), { description = "Switch To Context 10" })

-- ── Move Active Window to Workspace (Context Relative) ───────────────────────

hl.bind("SUPER + 1", ws("movetoworkspace", 1),  { description = "Move To Context 1" })
hl.bind("SUPER + 2", ws("movetoworkspace", 2),  { description = "Move To Context 2" })
hl.bind("SUPER + 3", ws("movetoworkspace", 3),  { description = "Move To Context 3" })
hl.bind("SUPER + 4", ws("movetoworkspace", 4),  { description = "Move To Context 4" })
hl.bind("SUPER + 5", ws("movetoworkspace", 5),  { description = "Move To Context 5" })
hl.bind("SUPER + 6", ws("movetoworkspace", 6),  { description = "Move To Context 6" })
hl.bind("SUPER + 7", ws("movetoworkspace", 7),  { description = "Move To Context 7" })
hl.bind("SUPER + 8", ws("movetoworkspace", 8),  { description = "Move To Context 8" })
hl.bind("SUPER + 9", ws("movetoworkspace", 9),  { description = "Move To Context 9" })
hl.bind("SUPER + 0", ws("movetoworkspace", 10), { description = "Move To Context 10" })

-- ── Move Window Silently (Context Relative) ───────────────────────────────────

hl.bind("SUPER + ALT + 1", ws("movetoworkspacesilent", 1),  { description = "Silent Move To Context 1" })
hl.bind("SUPER + ALT + 2", ws("movetoworkspacesilent", 2),  { description = "Silent Move To Context 2" })
hl.bind("SUPER + ALT + 3", ws("movetoworkspacesilent", 3),  { description = "Silent Move To Context 3" })
hl.bind("SUPER + ALT + 4", ws("movetoworkspacesilent", 4),  { description = "Silent Move To Context 4" })
hl.bind("SUPER + ALT + 5", ws("movetoworkspacesilent", 5),  { description = "Silent Move To Context 5" })
hl.bind("SUPER + ALT + 6", ws("movetoworkspacesilent", 6),  { description = "Silent Move To Context 6" })
hl.bind("SUPER + ALT + 7", ws("movetoworkspacesilent", 7),  { description = "Silent Move To Context 7" })
hl.bind("SUPER + ALT + 8", ws("movetoworkspacesilent", 8),  { description = "Silent Move To Context 8" })
hl.bind("SUPER + ALT + 9", ws("movetoworkspacesilent", 9),  { description = "Silent Move To Context 9" })
hl.bind("SUPER + ALT + 0", ws("movetoworkspacesilent", 10), { description = "Silent Move To Context 10" })


